// Fonction pour calculer la distance entre deux points
function distanceEuclidienne(point1, point2) {
  return Math.sqrt(Math.pow(point2.x - point1.x, 2) + Math.pow(point2.y - point1.y, 2));
}

// Fonction pour calculer la somme des distances d'une trajectoire
function calculerSommeDistance(trajectoire) {
  let sommeDistance = 0;
  for (let i = 1; i < trajectoire.length; i++) {
    sommeDistance += distanceEuclidienne(trajectoire[i - 1], trajectoire[i]);
  }
  return sommeDistance;
}

// Fonction pour calculer le temps d'une trajectoire
function calculerTemps(trajectoire, vitesse) {
  let sommeDistance = calculerSommeDistance(trajectoire);
  return sommeDistance / vitesse;
}

// Fonction pour calculer la répartition des distances (optionnel)
function calculerRepartitionDistance(trajectoire, temps1, temps2) {
  let distance1 = 0;
  let distance2 = 0;
  for (let i = 1; i < trajectoire.length; i++) {
    let distance = distanceEuclidienne(trajectoire[i - 1], trajectoire[i]);
    if (i <= trajectoire.length / 2) {
      distance1 += distance;
    } else {
      distance2 += distance;
    }
  }
  return distance1 / (distance1 + distance2);
}

// Fonction pour calculer la longueur de la trajectoire en fonction du nombre de caractères (optionnel)
function calculerLongueurTrajectoire(trajectoire) {
  return trajectoire.length;
}

// Fonction principale pour analyser la trajectoire
function euclideanTrajectory(trajectoire, vitesse) {
  let sommeDistance = calculerSommeDistance(trajectoire);
  let sommeTemps = calculerTemps(trajectoire, vitesse);
  console.log("Somme des distances : ", sommeDistance);
  console.log("Somme des temps : ", sommeTemps);
  // Calcul de la répartition des distances (optionnel)
  let repartitionDistance = calculerRepartitionDistance(trajectoire, sommeTemps / 2, sommeTemps);
  console.log("Répartition des distances : ", repartitionDistance);
  // Calcul de la longueur de la trajectoire en fonction du nombre de caractères (optionnel)
  let longueurTrajectoire = calculerLongueurTrajectoire(trajectoire);
  console.log("Longueur de la trajectoire : ", longueurTrajectoire);
}

// Exemple d'utilisation
let trajectoire = [
  { x: 0, y: 0 },
  { x: 3, y: 4 },
  { x: 6, y: 8 },
  { x: 9, y: 12 },
  { x: 12, y: 16 },
  { x: 15, y: 20 },
];

let vitesse = 5;
euclideanTrajectory(trajectoire, vitesse);
```

Ce code définit les fonctions pour calculer la distance entre deux points, la somme des distances d'une trajectoire, le temps d'une trajectoire, la répartition des distances et la longueur de la trajectoire en fonction du nombre de caractères. La fonction principale `euclideanTrajectory` appelle ces fonctions et affiche les résultats.

Notez que les fonctions `calculerRepartitionDistance` et `calculerLongueurTrajectoire` sont optionnelles et peuvent être supprimées si vous ne les utilisez pas.

