```javascript
function lancerDe() {
    return Math.floor(Math.random() * 6) + 1;
}

function jouer() {
    let joueur1 = false;
    let joueur2 = false;
    let tour = 1;

    while (!joueur1 && !joueur2) {
        console.log(`Tour ${tour}:`);

        const resultatJoueur1 = lancerDe();
        console.log(`Joueur 1 lance le dé et obtient: ${resultatJoueur1}`);
        if (resultatJoueur1 === 6) {
            joueur1 = true;
            break;
        }

        const resultatJoueur2 = lancerDe();
        console.log(`Joueur 2 lance le dé et obtient: ${resultatJoueur2}`);
        if (resultatJoueur2 === 6) {
            joueur2 = true;
            break;
        }

        tour++;
    }

    if (joueur1) {
        console.log("Joueur 1 gagne !");
    } else if (joueur2) {
        console.log("Joueur 2 gagne !");
    }
}

jouer();
```

